```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <variant>
#include <vector>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

// Helper: map table name to concrete type
inline std::string normalize_table_name(const std::string& name) {
  std::string n = name;
  for (auto& c : n) c = static_cast<char>(::tolower(c));
  return n;
}

template <typename F>
auto dispatch_table(const std::string& table_name, F&& f) {
  const auto t = normalize_table_name(table_name);
  if (t == "student") {
    return f.template operator()<Student>();
  } else if (t == "course") {
    return f.template operator()<Course>();
  } else if (t == "score") {
    return f.template operator()<Score>();
  } else if (t == "major") {
    return f.template operator()<Major>();
  }
  throw std::runtime_error("Unknown table name: " + table_name);
}

// 1. Insert records
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  if (records.empty()) return;

  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto& conn = conn_res.value();

  // we trust caller that T matches table_name; just insert
  for (const auto& rec : records) {
    auto r = sqlgen::insert(rec)(conn);
    if (!r) {
      throw std::runtime_error("Insert failed for table " + table_name);
    }
  }
}

// Helper type to carry new_value of different types
using SqlValue = std::variant<int64_t, double, std::string>;

// 2. Modify record by primary key ID
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const SqlValue& new_value) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto& conn = conn_res.value();

  auto run_for_table = [&](auto tag) {
    using T = decltype(tag);
    using Row = T;

    // Build "UPDATE <Table> SET <col> = ? WHERE <pk> = ?"
    constexpr auto tbl = sqlgen::table<Row>.name();
    const std::string pk_name = std::string(sqlgen::primary_key<Row>.name());
    std::string sql = "UPDATE ";
    sql += tbl;
    sql += " SET ";
    sql += col_name;
    sql += " = ? WHERE ";
    sql += pk_name;
    sql += " = ?;";

    auto stmt_res = sqlgen::prepare(conn, sql);
    if (!stmt_res) throw std::runtime_error("Failed to prepare statement");
    auto stmt = std::move(stmt_res.value());

    // bind new_value
    std::visit(
        [&](auto&& v) {
          using V = std::decay_t<decltype(v)>;
          if constexpr (std::is_same_v<V, int64_t>) {
            sqlgen::bind(stmt, 1, v);
          } else if constexpr (std::is_same_v<V, double>) {
            sqlgen::bind(stmt, 1, v);
          } else if constexpr (std::is_same_v<V, std::string>) {
            sqlgen::bind(stmt, 1, v);
          }
        },
        new_value);

    // pk type differs by table: parse accordingly
    if constexpr (std::is_same_v<Row, Student>) {
      sqlgen::bind(stmt, 2, record_id);  // SNo varchar
    } else {
      // integer primary key
      auto id = static_cast<int64_t>(std::stoll(record_id));
      sqlgen::bind(stmt, 2, id);
    }

    auto exec_res = sqlgen::step(stmt);
    if (!exec_res) throw std::runtime_error("Failed to execute update");
  };

  dispatch_table(
      table_name,
      [&](auto type_tag = typename std::remove_reference_t<decltype(type_tag)>{}) {
        using T = decltype(type_tag);
        run_for_table(T{});
      });
}

// Overload with typed new_value for convenience
template <typename V>
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const V& new_value) {
  SqlValue v;
  if constexpr (std::is_integral_v<V>) {
    v = static_cast<int64_t>(new_value);
  } else if constexpr (std::is_floating_point_v<V>) {
    v = static_cast<double>(new_value);
  } else if constexpr (std::is_same_v<V, std::string>) {
    v = new_value;
  } else if constexpr (std::is_same_v<V, const char*>) {
    v = std::string(new_value);
  } else {
    static_assert(sizeof(V) == 0, "Unsupported value type for modify_eas_records_by_id");
  }
  modify_eas_records_by_id(table_name, record_id, col_name, v);
}

// 3. Delete record by primary key ID
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_res = sqlgen::sqlite::connect(db_path);
  if (!conn_res) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto& conn = conn_res.value();

  auto run_for_table = [&](auto tag) {
    using Row = decltype(tag);

    constexpr auto tbl = sqlgen::table<Row>.name();
    const std::string pk_name = std::string(sqlgen::primary_key<Row>.name());

    std::string sql = "DELETE FROM ";
    sql += tbl;
    sql += " WHERE ";
    sql += pk_name;
    sql += " = ?;";

    auto stmt_res = sqlgen::prepare(conn, sql);
    if (!stmt_res) throw std::runtime_error("Failed to prepare delete");
    auto stmt = std::move(stmt_res.value());

    if constexpr (std::is_same_v<Row, Student>) {
      // SNo is varchar
      sqlgen::bind(stmt, 1, record_id);
    } else {
      // numeric PK
      auto id = static_cast<int64_t>(std::stoll(record_id));
      sqlgen::bind(stmt, 1, id);
    }

    auto exec_res = sqlgen::step(stmt);
    if (!exec_res) throw std::runtime_error("Failed to execute delete");
  };

  dispatch_table(
      table_name,
      [&](auto type_tag = typename std::remove_reference_t<decltype(type_tag)>{}) {
        using T = decltype(type_tag);
        run_for_table(T{});
      });
}
