#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <iostream>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  try {
    // Connect to SQLite database
    sqlgen::sqlite::Database db{"test_db.sqlite"};

    // Drop Product table if it exists
    db.execute(R"(
      DROP TABLE IF EXISTS Product;
    )");

    // Create Product table
    db.execute(R"(
      CREATE TABLE Product (
        product_id INTEGER PRIMARY KEY,
        name       VARCHAR(100) NOT NULL,
        price      REAL         NOT NULL,
        category   VARCHAR(50)  NOT NULL,
        stock      INTEGER      NOT NULL DEFAULT 0
      );
    )");

    // Create ORM table helper
    sqlgen::Table<Product> product_table{"Product"};

    // Begin transaction
    db.begin_transaction();

    // Batch insert all products
    for (const auto& p : products) {
      product_table.insert(db, p);
    }

    // Commit transaction if all inserts succeed
    db.commit_transaction();
    return true;
  } catch (const std::exception&) {
    // Rollback on any error and return false
    try {
      sqlgen::sqlite::Database db{"test_db.sqlite"};
      db.rollback_transaction();
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace batch_insert_products
