std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn{"test_db.sqlite"};

  // Create tables for the schema (no-op if they already exist)
  sqlite::create_table<Customer>(conn);
  sqlite::create_table<Product>(conn);
  sqlite::create_table<Order>(conn);
  sqlite::create_table<OrderItem>(conn);

  // Prepare SQL query to retrieve purchase history
  const char* sql = R"SQL(
    SELECT p.name, o.order_date, oi.quantity
    FROM Customer c
    JOIN "Order" o ON c.customer_id = o.customer_id
    JOIN OrderItem oi ON o.order_id = oi.order_id
    JOIN Product p ON oi.product_id = p.product_id
    WHERE c.customer_id = ?
    ORDER BY o.order_date DESC;
  )SQL";

  sqlite::Statement stmt{conn, sql};
  stmt.bind(1, customer_id);

  std::vector<PurchaseHistory> history;

  while (stmt.step()) {
    PurchaseHistory row;
    row.product_name = stmt.column<std::string>(0);
    row.order_date = stmt.column<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">>(1);
    row.quantity = stmt.column<int>(2);
    history.push_back(std::move(row));
  }

  return history;
}

