struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  // Open connection to SQLite database "test_db.sqlite"
  sqlgen::sqlite::Connection conn{"test_db.sqlite"};

  // Create a query builder for the Book table
  auto query = sqlgen::make_query<Book>();

  bool has_filter = false;

  // Add filters dynamically based on non-null input parameters

  // Title keyword: use LIKE with wildcards
  if (filters.title_keyword.has_value()) {
    std::string pattern = "%" + *filters.title_keyword + "%";
    query = query.where(&Book::title, sqlgen::like, pattern);
    has_filter = true;
  }

  // Minimum year: year >= min_year
  if (filters.min_year.has_value()) {
    query = query.where(&Book::year, sqlgen::ge, *filters.min_year);
    has_filter = true;
  }

  // Genre: exact match
  if (filters.genre.has_value()) {
    query = query.where(&Book::genre, sqlgen::eq, *filters.genre);
    has_filter = true;
  }

  // Maximum price: price <= max_price
  if (filters.max_price.has_value()) {
    query = query.where(&Book::price, sqlgen::le, *filters.max_price);
    has_filter = true;
  }

  // Execute the query and return the results
  // If no filters are provided, this returns all books
  std::vector<Book> results = query.exec(conn);

  return results;
}

}  // namespace query_search_books_by_criteria
