          std::make_integer_sequence<int, rfl::tuple_size_v<Fields>>()),
      .if_not_exists = _if_not_exists};
}

template <class OtherType>
auto operator|(const OtherType& _o, const IfNotExists&) {
  auto o = _o;
  o.if_not_exists_ = true;
  return o;
}

