/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  try {
    // Open / connect to the SQLite database
    sqlgen::sqlite::Connection conn{"test_db.sqlite"};

    // We assume the "User" table already exists with columns:
    //   user_id, username
    //
    // We want to add:
    //   phone_number VARCHAR(20)
    //   is_active INTEGER DEFAULT 1
    //
    // Use raw ALTER TABLE statements; if a column already exists,
    // SQLite will raise an error. We catch and interpret those.

    auto columnExistsError = [](const std::string &msg) -> bool {
      // SQLite does not have a dedicated "column exists" error code for
      // ALTER TABLE ADD COLUMN, so in practice different builds/drivers
      // may expose slightly different messages.  We conservatively
      // treat "duplicate column name" as "column already exists".
      return msg.find("duplicate column name") != std::string::npos ||
             msg.find("already exists") != std::string::npos;
    };

    // 1) Add phone_number column
    try {
      conn.execute(
          "ALTER TABLE User ADD COLUMN phone_number VARCHAR(20);");
    } catch (const std::exception &e) {
      std::string msg = e.what();
      if (!columnExistsError(msg)) {
        std::cerr << "Error adding column phone_number: " << msg << '\n';
        return false;
      }
      // If the column already exists, we ignore and continue.
    }

    // 2) Add is_active column (boolean represented as INTEGER, default 1)
    try {
      conn.execute(
          "ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1;");
    } catch (const std::exception &e) {
      std::string msg = e.what();
      if (!columnExistsError(msg)) {
        std::cerr << "Error adding column is_active: " << msg << '\n';
        return false;
      }
      // If the column already exists, we ignore and continue.
    }

    // Optionally, we could verify the final schema by reflecting into UserAfter
    // via sqlgen if desired, but the problem statement only requires the ALTERs.

    return true;
  } catch (const std::exception &e) {
    std::cerr << "Migration failed: " << e.what() << '\n';
    return false;
  }
}

} // namespace schema_migration_add_column
