namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  if (ids.empty()) {
    return true;  // Nothing to delete, treat as success
  }

  try {
    // Open SQLite database
    sqlgen::sqlite::Connection conn{"test_db.sqlite"};

    // Map the Document struct to the "Document" table
    sqlgen::Mapper<Document> mapper{
        conn,
        "Document",
        &Document::doc_id,
        &Document::title,
        &Document::is_deleted,
        &Document::deleted_at};

    // Start a transaction so the operation is atomic
    sqlgen::Transaction txn{conn};

    // Build a query with an IN clause over the list of ids
    auto q = mapper.query();
    q.where(q.col(&Document::doc_id).in(ids));

    // Perform a bulk update: set is_deleted = 1 and deleted_at = CURRENT_TIMESTAMP
    // Using CURRENT_TIMESTAMP via a raw SQL expression so that it is evaluated by SQLite.
    std::size_t affected = q.update({
        {&Document::is_deleted, 1},
        {&Document::deleted_at, sqlgen::raw("CURRENT_TIMESTAMP")}
    });

    // Commit the transaction
    txn.commit();

    // Return true if at least one row was updated
    return affected > 0;
  } catch (...) {
    // In a real application, you would log the error.
    return false;
  }
}

}  // namespace soft_delete_records
