namespace transaction_transfer_funds {

TEST(sqlite, transaction_transfer_funds) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Account>(conn);
  create_table<Account>(conn);

  insert(conn, std::vector<Account>{{1, 100.0}, {2, 50.0}});

  ASSERT_TRUE(transfer_funds(1, 2, 30.0));
  auto rows = sqlgen::read<std::vector<Account>>(conn).value();
  auto find = [&](int id) {
    return std::find_if(rows.begin(), rows.end(),
                        [&](const Account& a) { return a.account_id.value() == id; });
  };
  EXPECT_DOUBLE_EQ(find(1)->balance, 70.0);
  EXPECT_DOUBLE_EQ(find(2)->balance, 80.0);

  ASSERT_FALSE(transfer_funds(1, 2, 100.0));
  rows = sqlgen::read<std::vector<Account>>(conn).value();
  EXPECT_DOUBLE_EQ(find(1)->balance, 70.0);
  EXPECT_DOUBLE_EQ(find(2)->balance, 80.0);
}

