void update_eas_table() {
  // Ensure initial schema (including Major) exists
  design_eas_database_with_major();

  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    conn_result.error().throw_exception();
  }
  auto& conn = conn_result.value();

  // 1. Add new column Grade to Score: char(1) NOT NULL
  {
    // SQLite uses TEXT; we specify length in definition for clarity
    auto res = sqlgen::exec(
        conn,
        "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT ' ';");
    if (!res) {
      res.error().throw_exception();
    }
  }

  // 2. Modify column type of Age in Student to int NULLABLE
  {
    // SQLite doesn't support MODIFY COLUMN directly; typical pattern is
    // to recreate the table. Here we assume Age already exists and
    // simply relax type to INTEGER allowing NULLs via a recreate.
    //
    // To avoid over-complication and because the task explicitly
    // requires changing the type, we issue a sequence of SQL commands
    // performing the usual migration pattern.

    const char* sql_migration =
        "PRAGMA foreign_keys = OFF;"
        "BEGIN TRANSACTION;"
        "CREATE TABLE Student_new ("
        "  SNo VARCHAR(10) PRIMARY KEY,"
        "  SName VARCHAR(30) NOT NULL,"
        "  Sex INTEGER NOT NULL DEFAULT 1,"
        "  Birthday DATETIME,"
        "  Major INTEGER,"
        "  Scorses REAL,"
        "  Remark TEXT,"
        "  Age INTEGER"
        ");"
        "INSERT INTO Student_new (SNo, SName, Sex, Birthday, Major, Scorses, Remark, Age) "
        "SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark, Age FROM Student;"
        "DROP TABLE Student;"
        "ALTER TABLE Student_new RENAME TO Student;"
        "COMMIT;"
        "PRAGMA foreign_keys = ON;";

    auto res = sqlgen::exec(conn, sql_migration);
    if (!res) {
      res.error().throw_exception();
    }
  }

  // 3. Drop table Major
  {
    auto res = sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
    if (!res) {
      res.error().throw_exception();
    }
  }
}

} // namespace update_eas_table
