  using namespace sqlgen;

  // Open SQLite connection
  sqlite::Connection conn("test_db.sqlite");

  // Create ORM instance for the Order table
  Orm<Order> orm(conn, "Order");

  int total_affected = 0;

  // 1) Update 'pending' orders older than 7 days to 'expired'
  {
    // Equivalent SQL:
    // UPDATE "Order"
    // SET status = 'expired'
    // WHERE status = 'pending'
    //   AND order_date < DATE('now', '-7 days');
    auto affected = orm.update()
      .set(&Order::status, "expired")
      .where(
        c(&Order::status) == "pending" &&
        raw("order_date < DATE('now', '-7 days')")
      )
      .execute();

    total_affected += affected;
  }

  // 2) Update 'shipped' orders to 'delivered'
