#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  // Mark this as a view so sqlgen treats it appropriately
  static constexpr bool is_view = true;

  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 *
 * Reference SQL:
 *   CREATE VIEW SalesSummary AS
 *   SELECT p.name as product_name,
 *          SUM(s.quantity) as total_quantity,
 *          SUM(s.amount) as total_revenue
 *   FROM Sale s
 *   JOIN Product p ON s.product_id = p.product_id
 *   GROUP BY p.name;
 *
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;

  try {
    // 1. Connect to the SQLite database "test_db.sqlite"
    sqlite::connection conn{"test_db.sqlite"};

    // 2. Manually drop the view if it exists (SQLite lacks DROP VIEW IF EXISTS
    //    in very old versions; this is defensive and portable).
    {
      auto drop_stmt = conn.prepare(
          "DROP VIEW IF EXISTS SalesSummary;");
      drop_stmt.execute();
    }

    // 3. Construct the SELECT query for the view using sqlgen query builder
    //    (equivalent to the reference SQL above).
    //
    //    SELECT p.name as product_name,
    //           SUM(s.quantity) as total_quantity,
    //           SUM(s.amount) as total_revenue
    //    FROM Sale s
    //    JOIN Product p ON s.product_id = p.product_id
    //    GROUP BY p.name;
    //
    // Note: We use aggregate expressions and aliases that match the
    //       SalesSummary struct fields.
    auto s = alias<Sale>("s");
    auto p = alias<Product>("p");

    // Build the SELECT expression
    auto select_stmt =
        select(
            column(p, &Product::name).as("product_name"),
            func<sum>(column(s, &Sale::quantity)).as("total_quantity"),
            func<sum>(column(s, &Sale::amount)).as("total_revenue"))
            .from(s)
            .join(p, column(s, &Sale::product_id) ==
                        column(p, &Product::product_id))
            .group_by(column(p, &Product::name));

    // 4. Use sqlgen's create_view (or create_as) command for the view
    //    definition. We pass the SELECT statement constructed above.
    auto view_sql = to_sql(
        create_view<SalesSummary>("SalesSummary").as(select_stmt));

    // 5. Execute the CREATE VIEW statement
    {
      auto create_stmt = conn.prepare(view_sql);
      create_stmt.execute();
    }

    return true;
  } catch (const std::exception &) {
    // In a real application, log the exception here.
    return false;
  }
}

}  // namespace schema_create_view_sales_summary
