/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db{"test_db.sqlite"};

  // Build a query that behaves like a RIGHT JOIN of Project to Department.
  // Since many SQL dialects (including SQLite) do not support RIGHT JOIN directly,
  // we emulate it by using a LEFT JOIN from Department to Project, ensuring
  // all departments are included (even those without any project).
  //
  // Logical RIGHT JOIN wanted:
  //   SELECT d.name, p.name
  //   FROM Project p
  //   RIGHT JOIN Department d ON p.department_id = d.department_id;
  //
  // Emulated in SQLite as:
  //   SELECT d.name, p.name
  //   FROM Department d
  //   LEFT JOIN Project p ON d.department_id = p.department_id;
  //
  // We follow that pattern with sqlgen.

  auto q = select(Department::name, Project::name)
             .from<Department>()
             .left_join<Project>(on(Department::department_id == Project::department_id));

  // Execute the query and collect results into DepProj.
  // Department name can be null if the join fails on that side, so we map it
  // into std::optional<std::string>. Project name is required by DepProj's
  // definition, but logically it may be null for departments without projects.
  // Here we convert null project_name to an empty string to keep the interface
  // simple, while still demonstrating that the department is present.
  std::vector<DepProj> result;
  db.read(q, [&](std::optional<std::string> dept_name,
                 std::optional<std::string> proj_name) {
    DepProj row;
    row.department_name = dept_name;               // may be std::nullopt
    row.project_name = proj_name.value_or("");     // empty if no project
    result.emplace_back(std::move(row));
  });

  return result;
}

}  // namespace right_join_departments_projects
