  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // Bind the Event struct to a table named "Event"
  auto eventTable = make_table<Event>("Event");

  // Create the Event table if it does not already exist
  eventTable.create_if_not_exists(conn);

