           .where(Raw<bool>("end_time IS NOT NULL"));

  for (auto row : q.execute(conn)) {
    TemporalAnalysis ta;
    ta.event_id       = row.get<0>();
    ta.event_name     = row.get<1>();
    ta.start_day      = row.get<2>();
    ta.start_month    = row.get<3>();
