    // upserts, invoking a write on an existing primary key will replace the row
    // and insert a new one otherwise.
    {
      auto tx = conn.transaction();  // optional but good practice

      for (const auto& item : items) {
        // This will insert a new row or replace the existing one based on the
        // primary key 'item_id'.
        conn.write(item);
      }

      tx.commit();
