  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a SQLite Product table in "test_db.sqlite" (creating the
 * table if needed) and run a SELECT that computes various mathematical
 * expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;

  // Open (or create) the database
  sqlite::Database db{"test_db.sqlite"};

  // Ensure the Product table exists with the expected schema
  {
    const char* create_sql = R"SQL(
      CREATE TABLE IF NOT EXISTS Product (
        product_id    INTEGER PRIMARY KEY,
        name          TEXT NOT NULL,
        price         REAL NOT NULL,
        quantity      INTEGER NOT NULL,
        discount_rate REAL NOT NULL
      );
    )SQL";

    sqlite::Statement stmt{db, create_sql};
    stmt.execute();
  }

  // Clear existing rows so analysis reflects only the provided products
  {
    const char* delete_sql = "DELETE FROM Product;";
    sqlite::Statement stmt{db, delete_sql};
    stmt.execute();
  }

  // Insert provided products
  {
    const char* insert_sql =
        "INSERT INTO Product (product_id, name, price, quantity, discount_rate) "
        "VALUES (?, ?, ?, ?, ?);";
    sqlite::Statement stmt{db, insert_sql};

    for (const auto& p : products) {
      stmt.reset();
      stmt.bind(1, static_cast<int>(p.product_id));  // PrimaryKey wrapper -> value
      stmt.bind(2, p.name);
      stmt.bind(3, p.price);
      stmt.bind(4, p.quantity);
      stmt.bind(5, p.discount_rate);
      stmt.execute();
    }
  }

  // SQLite does not have CEIL / LN / LOG2 built-in under those names.
  // We will compute them in C++ after selecting raw values.
  const char* select_sql = R"SQL(
    SELECT
      product_id,
      name,
      price,
      quantity,
      discount_rate
    FROM Product;
  )SQL";

  sqlite::Statement stmt{db, select_sql};

  std::vector<MathAnalysis> result;
  while (stmt.step()) {
    MathAnalysis m{};

    // Basic columns
    m.product_id = stmt.get<int>(0);
    m.name       = stmt.get<std::string>(1);
    double price = stmt.get<double>(2);
    int quantity = stmt.get<int>(3);
    double discount_rate = stmt.get<double>(4);

    // 1. Absolute, ceil, floor, rounded
    m.abs_price     = std::fabs(price);
    m.ceil_price    = std::ceil(price);
    m.floor_price   = std::floor(price);
    // Emulate ROUND(price, 2)
    {
      double scale = 100.0;
      m.rounded_price = std::round(price * scale) / scale;
    }

    // 2. Trigonometric calculations (using discount_rate in radians)
    m.sin_discount = std::sin(discount_rate);
    m.cos_discount = std::cos(discount_rate);
    m.tan_discount = std::tan(discount_rate);

    // 3. Exponential and logarithmic functions
    //    EXP(discount_rate/100)
    m.exp_discount = std::exp(discount_rate / 100.0);

    //    LN(price) -> natural log
    m.ln_price = (price > 0.0) ? std::log(price) : std::numeric_limits<double>::quiet_NaN();

    //    LOG2(quantity)
    m.log2_quantity =
        (quantity > 0) ? std::log2(static_cast<double>(quantity))
                       : std::numeric_limits<double>::quiet_NaN();

    // 4. SQRT(quantity)
    m.sqrt_quantity =
        (quantity >= 0) ? std::sqrt(static_cast<double>(quantity))
                        : std::numeric_limits<double>::quiet_NaN();

    result.push_back(std::move(m));
  }

  return result;
}

}  // namespace mathematical_operations_analysis

