std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // Ensure the OrderItem table exists (schema as described by the user).
  // Types and constraints are aligned with the provided table structure.
  db.execute(R"SQL(
    CREATE TABLE IF NOT EXISTS OrderItem (
      item_id      INTEGER PRIMARY KEY,
      order_id     INTEGER NOT NULL,
      product_id   INTEGER NOT NULL,
      unit_price   REAL    NOT NULL,
      quantity     INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate      REAL
    );
  )SQL");

  // Clear existing contents so that analysis is performed only on the provided items
  db.execute("DELETE FROM OrderItem;");

  // Insert provided items into the OrderItem table using sqlgen
  {
    auto inserter = sql(db).insert_into<OrderItem>();
    for (const auto& it : items) {
