  //   (unit_price * quantity / quantity) as unit_cost,
  //   (quantity % 10) as quantity_group,
  //   (unit_price * 0.3) as estimated_profit
  // FROM OrderItem;

  // Using sqlgen's DSL to express the same query.
  // For simplicity and clarity, we use a raw SQL query here; sqlgen fully supports
  // executing raw statements and mapping by column index.
  sqlite::Statement stmt = db.prepare(R"SQL(
