struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::connection conn("test_db.sqlite");

  // Define the table mapping for Note
  auto notes_table = make_table(
      "Notes",
      make_column("note_id", &Note::note_id, primary_key()),
      make_column("content", &Note::content));

  // Create a context for executing queries
  auto ctx = make_context(conn, notes_table);

  // 1. Update: replace all occurrences of "foo" with "bar" in content
  //    Using SQLite REPLACE function: content = REPLACE(content, 'foo', 'bar')
  ctx.update(notes_table)
      .set(notes_table.col(&Note::content) =
               function("REPLACE",
                        notes_table.col(&Note::content),
                        value("foo"),
                        value("bar")))
      .exec();

  // 2. Query back the updated rows for verification
  std::vector<UpdatedNote> result;
  result.reserve(64);  // arbitrary small pre-reserve

  ctx.select(notes_table.col(&Note::note_id),
             notes_table.col(&Note::content))
      .from(notes_table)
      .exec([&result](const Note& note_row) {
        UpdatedNote updated;
        updated.note_id = note_row.note_id;
        updated.updated_content = note_row.content;
        result.emplace_back(std::move(updated));
      });

  return result;
}

}  // namespace replace_text_in_notes

