#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;

  // Open or create SQLite database
  sqlite::Database db("test_db.sqlite");

  // Ensure foreign keys are enforced (required by SQLite)
  db.execute("PRAGMA foreign_keys = ON;");

  // Create tables with proper constraints
  // sqlgen will generate:
  // Parent: parent_id PRIMARY KEY, name NOT NULL
  db.create_table_if_not_exists<Parent>();

  // For Child, generate table then adjust FK to ensure ON DELETE CASCADE
  db.create_table_if_not_exists<Child>();

  // Replace the Child table with one that has ON DELETE CASCADE explicitly
  // (if sqlgen doesn't already emit it by default)
  db.execute("DROP TABLE IF EXISTS Child;");
  db.execute(
      "CREATE TABLE Child ("
      "  child_id   INTEGER PRIMARY KEY,"
      "  parent_id  INTEGER,"
      "  note       TEXT,"
      "  FOREIGN KEY(parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE"
      ");");

  // Clear any old data
  db.execute("DELETE FROM Child;");
  db.execute("DELETE FROM Parent;");

  // Insert a parent row
  {
    auto stmt = db.insert_into<Parent>();
    Parent p;
    p.parent_id = 1;
    p.name = "Parent 1";
    stmt.values(p).execute();
  }

  // Insert a child row referring to that parent
  {
    auto stmt = db.insert_into<Child>();
    Child c;
    c.child_id = 1;
    c.parent_id = 1;
    c.note = "Child of Parent 1";
    stmt.values(c).execute();
  }

  // Delete the parent row (should cascade to Child)
  {
    auto stmt = db.delete_from<Parent>().where(c("parent_id") == 1);
    stmt.execute();
  }

  // Verify that the child row was deleted automatically
  std::size_t child_count = 0;
  {
    auto stmt = db.select_from<Child>().count();
    stmt.execute().get(child_count);
  }

  // If cascade worked, there should be 0 child rows
  return child_count == 0;
}

}  // namespace cascade_delete_demo
