 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;

  try {
    // Connect to SQLite database
    sqlite::database db("test_db.sqlite");

    // Create the Account table
    {
      auto schema = make_schema(
          "Account",
          &Account::account_id,
          &Account::balance,
          &Account::status);

      db.execute(schema.create_table_sql());
    }

    // Insert sample data
    {
      auto writer = make_writer<Account>(db, "Account");

      Account a1{1, 100.0, "active"};
      Account a2{2, 200.0, "active"};
      Account a3{3, 300.0, "inactive"};

      writer.insert(a1);
      writer.insert(a2);
      writer.insert(a3);
    }

    // Update balances and statuses using set(...)
    {
      auto writer = make_writer<Account>(db, "Account");

      // Example 1: Update a single row (account_id = 1)
      writer.update()
          .set(&Account::balance, 150.0)
          .set(&Account::status, std::string("active"))
          .where(eq(&Account::account_id, 1))
          .execute();

      // Example 2: Bulk update based on condition
      // Increase balance by 50 for all active accounts
      writer.update()
          .set(&Account::balance, 250.0)
          .where(eq(&Account::account_id, 2))
          .execute();

      // Example 3: Change status of inactive accounts
      writer.update()
          .set(&Account::status, std::string("closed"))
          .where(eq(&Account::status, std::string("inactive")))
          .execute();
    }

    // Verify changes persisted
    {
      auto reader = make_reader<Account>(db, "Account");

      std::vector<Account> accounts;
      reader.select().execute(accounts);

      bool found1 = false, found2 = false, found3 = false;

