```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 *
 * Demonstrates a FULL JOIN behavior between Supplier and Product tables using SQLite,
 * which does not support FULL OUTER JOIN natively. We emulate FULL JOIN by:
 *
 *   1. LEFT JOIN:  all suppliers with their products (if any)
 *   2. RIGHT JOIN emulation: all products whose suppliers do not exist (orphan products)
 *   3. UNION of the two result sets
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Open connection to SQLite database "test_db.sqlite"
  sqlgen::sqlite::connection db("test_db.sqlite");

  std::vector<SupProd> results;

  // ---------------------------------------------------------------------------
  // Part 1: LEFT JOIN – all suppliers plus any matching products
  // ---------------------------------------------------------------------------
  {
    // Using sqlgen's DSL to construct:
    //   SELECT s.name AS supplier_name, p.name AS product_name
    //   FROM Supplier AS s
    //   LEFT JOIN Product AS p ON s.supplier_id = p.supplier_id;
    auto q = sqlgen::select(
                sqlgen::column(&Supplier::name).as("supplier_name"),
                sqlgen::column(&Product::name).as("product_name"))
             .from<Supplier>()
             .left_join<Product>(
                 sqlgen::on(&Supplier::supplier_id, &Product::supplier_id));

    auto stmt = db.prepare(q);

    // The result row will be a tuple-like structure that sqlgen can unpack.
    // We'll fetch the two projected columns into std::string / std::optional.
    std::string supplier_name;
    std::optional<std::string> product_name;

    while (stmt.step()) {
      stmt.get(0, supplier_name);

      // Column 1 (product_name) may be NULL (no matching product), so we check.
      if (stmt.is_null(1)) {
        product_name.reset();
      } else {
        std::string p;
        stmt.get(1, p);
        product_name = p;
      }

      results.push_back(SupProd{supplier_name, product_name});
    }
  }

  // ---------------------------------------------------------------------------
  // Part 2: RIGHT JOIN emulation – orphan products (products without a Supplier)
  // SQLite has no RIGHT/FULL JOIN, so we explicitly select products whose
  // supplier_id is not found in Supplier.
  //
  // Equivalent SQL:
  //   SELECT '(no supplier)' AS supplier_name, p.name AS product_name
  //   FROM Product AS p
  //   LEFT JOIN Supplier AS s ON p.supplier_id = s.supplier_id
  //   WHERE s.supplier_id IS NULL;
  // ---------------------------------------------------------------------------
  {
    auto q_orphans =
        sqlgen::select(
            // A literal string used as supplier_name when there is no supplier
            sqlgen::value(std::string("(no supplier)")).as("supplier_name"),
            sqlgen::column(&Product::name).as("product_name"))
        .from<Product>()
        .left_join<Supplier>(
            sqlgen::on(&Product::supplier_id, &Supplier::supplier_id))
        .where(sqlgen::is_null(&Supplier::supplier_id));

    auto stmt = db.prepare(q_orphans);

    std::string supplier_name;
    std::optional<std::string> product_name;

    while (stmt.step()) {
      stmt.get(0, supplier_name);

      if (stmt.is_null(1)) {
        product_name.reset();
      } else {
        std::string p;
        stmt.get(1, p);
        product_name = p;
      }

      results.push_back(SupProd{supplier_name, product_name});
    }
  }

  return results;
}

}  // namespace full_join_suppliers_products
