/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::connection conn("test_db.sqlite");
  orm_schema schema(conn);

  // Register the tables based on the structs
  schema.register_table<Department>("Department",
                                    column(&Department::department_id, "department_id"),
                                    column(&Department::department_name, "department_name"),
                                    column(&Department::location, "location"));

  schema.register_table<Employee>("Employee",
                                  column(&Employee::employee_id, "employee_id"),
                                  column(&Employee::department_id, "department_id"),
                                  column(&Employee::first_name, "first_name"),
                                  column(&Employee::last_name, "last_name"),
                                  column(&Employee::salary, "salary"));

  // Create tables if they do not exist
  schema.create_all();

  // Clear existing data to make the analysis deterministic for the given inputs
  {
    sqlite::statement clear_emp(conn, "DELETE FROM Employee");
    clear_emp.execute();
    sqlite::statement clear_dept(conn, "DELETE FROM Department");
    clear_dept.execute();
  }

  // Insert provided departments and employees
  {
    auto dept_inserter = schema.get_table<Department>().inserter();
    for (const auto& d : depts) {
      dept_inserter.insert(d);
    }

    auto emp_inserter = schema.get_table<Employee>().inserter();
    for (const auto& e : emps) {
      emp_inserter.insert(e);
    }
  }

  JoinAnalysis analysis;

  // Helper lambda to execute a query and map results into JoinResult
  auto run_query = [&conn](const std::string& sql,
                           std::vector<JoinResult>& out_vec) {
    sqlite::statement stmt(conn, sql);

    while (stmt.step()) {
      JoinResult jr;

      // Column order is: department_name, first_name, last_name, salary
      if (!stmt.is_null(0)) {
        jr.department_name = stmt.get<std::string>(0);
      }
      if (!stmt.is_null(1)) {
        jr.first_name = stmt.get<std::string>(1);
      }
      if (!stmt.is_null(2)) {
        jr.last_name = stmt.get<std::string>(2);
      }
      if (!stmt.is_null(3)) {
        jr.salary = stmt.get<double>(3);
      }

      out_vec.push_back(std::move(jr));
    }
  };

  // 1. INNER JOIN: employees with assigned departments
  const std::string inner_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id";

  run_query(inner_join_sql, analysis.inner_join_results);

  // 2. LEFT JOIN: all employees, even without departments
  // (Employee left join Department)
  const std::string left_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id";

  run_query(left_join_sql, analysis.left_join_results);

  // 3. RIGHT JOIN: all departments, even without employees
  // SQLite does not support RIGHT JOIN natively; emulate as:
  // RIGHT JOIN Employee e ON e.department_id = d.department_id
  //   <=> FROM Department d LEFT JOIN Employee e ON d.department_id = e.department_id
  const std::string right_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  run_query(right_join_sql, analysis.right_join_results);

  // 4. FULL JOIN: all employees and all departments
  // Emulate FULL OUTER JOIN with UNION of LEFT JOIN and RIGHT JOIN results,
  // eliminating duplicates.
  const std::string full_join_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  run_query(full_join_sql, analysis.full_join_results);

  return analysis;
}

}  // namespace analyze_department_employees
