```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;

  // Open SQLite connection to the given database
  sqlite::connection db("test_db.sqlite");

  // Table wrappers for sqlgen
  Table<Product> product_table("Product");
  Table<Sales> sales_table("Sales");

  // Build the query:
  // SELECT
  //   p.product_id,
  //   p.product_name,
  //   p.category,
  //   SUM(p.price * s.quantity) AS total_sales
  // FROM Product p
  // INNER JOIN Sales s ON p.product_id = s.product_id
  // GROUP BY p.product_id, p.product_name, p.category
  // ORDER BY total_sales DESC
  // LIMIT :limit;
  auto q = select(
              product_table.product_id,
              product_table.product_name,
              product_table.category,
              sum(product_table.price * sales_table.quantity).as("total_sales"))
           .from(product_table)
           .join(sales_table, product_table.product_id == sales_table.product_id)
           .group_by(product_table.product_id,
                     product_table.product_name,
                     product_table.category)
           .order_by(desc("total_sales"))
           .limit(parameter<int>("limit"));

  std::vector<TopProduct> results;

  // Execute the query with the supplied limit and map rows to TopProduct
  db.execute(
      q,
      parameters("limit", static_cast<int>(limit_count)),
      [&](int product_id,
          const std::string &product_name,
          const std::string &category,
          double total_sales) {
        results.push_back(
            TopProduct{product_id, product_name, category, total_sales});
      });

  return results;
}

}  // namespace get_top_products
```

