    auto q = update<Product>()
               .set("stock"_f = "stock"_f + p<int>("qty"))
               .where("product_id"_f == p<int>("pid"));

    // Execute the query with bound parameters to ensure safety
    auto exec_res = exec(txn, q, params("qty"_p = qty, "pid"_p = pid));
    if (!exec_res) {
      // On any failure, roll back the transaction and report failure
      (void)rollback(txn);
      return false;
    }
  }

  // Commit the transaction to ensure atomicity
  auto commit_res = commit(txn);
  return commit_res.has_value();
}

}  // namespace update_inventory_stock
