namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;         // 0 = Sunday, 1 = Monday, ..., 6 = Saturday (SQLite strftime('%w'))
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Open SQLite connection to the given database file.
  Connection conn{"test_db.sqlite"};

  // Define an aggregate result struct compatible with sqlgen's query mapping.
  struct AggRow {
    int weekday;        // result of strftime('%w', sale_time)
    int total_quantity; // SUM(quantity)
  };

  // Obtain table handle for Sales.
  auto sales = conn.table<Sales>("Sales");

  // Build and execute the aggregate query:
  // SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday,
  //        SUM(quantity) AS total_quantity
  // FROM Sales
  // GROUP BY weekday
  auto query = sales
      .select(
          Raw<int>("CAST(strftime('%w', sale_time) AS INTEGER)") >> &AggRow::weekday,
          sum(&Sales::quantity) >> &AggRow::total_quantity)
      .group_by(Raw<void>("strftime('%w', sale_time)"));

  std::vector<AggRow> agg_rows = query.all();

  // Convert query results into WeekdayStats for the public API.
  std::vector<WeekdayStats> results;
  results.reserve(agg_rows.size());
  for (const auto &row : agg_rows) {
    results.push_back(WeekdayStats{row.weekday, row.total_quantity});
  }

  return results;
}

}  // namespace weekday_sales_analysis
