  // is implemented as:
  //   CAST(strftime('%d', t.start_time) AS INTEGER)  AS day
  //   CAST(strftime('%m', t.start_time) AS INTEGER)  AS month
  //   CAST(strftime('%Y', t.start_time) AS INTEGER)  AS year
  //   CAST(strftime('%H', t.start_time) AS INTEGER)  AS hour
  //   CAST(strftime('%M', t.start_time) AS INTEGER)  AS minute
  //   CAST(strftime('%S', t.start_time) AS INTEGER)  AS second
  //   (julianday(t.end_time) - julianday(t.start_time)) AS duration_days
  //
  // For weekly grouping, we compute the ISO-like week number from start_time.
  // The query below returns one row per (project_id, year, week) with aggregated metrics.
  //
  // You can adjust aggregation logic as needed; here we:
  //   - Use MIN for date/time components (representative start of the week for that project)
  //   - SUM the total duration_days for the week.
  const char *sql = R"SQL(
    SELECT
      p.project_id AS project_id,
      p.name        AS name,
      -- representative date/time components (earliest in the week for that project)
      MIN(CAST(strftime('%d', t.start_time) AS INTEGER)) AS day,
      MIN(CAST(strftime('%m', t.start_time) AS INTEGER)) AS month,
      MIN(CAST(strftime('%Y', t.start_time) AS INTEGER)) AS year,
      MIN(CAST(strftime('%H', t.start_time) AS INTEGER)) AS hour,
      MIN(CAST(strftime('%M', t.start_time) AS INTEGER)) AS minute,
      MIN(CAST(strftime('%S', t.start_time) AS INTEGER)) AS second,
      -- total duration in days for the project-week
      SUM(julianday(t.end_time) - julianday(t.start_time)) AS duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
    -- weekly grouping (year + week number)
    GROUP BY
      p.project_id,
      p.name,
      strftime('%Y', t.start_time),
      strftime('%W', t.start_time)
    ORDER BY
      p.project_id,
      strftime('%Y', t.start_time),
      strftime('%W', t.start_time)
  )SQL";

  std::vector<TimeMetrics> results;

  // Prepare and execute using sqlgen's SQLite wrapper
  sqlite::Statement stmt{db, sql};

  while (stmt.step()) {
    TimeMetrics metrics{};

    // Column indices must match the SELECT order above
    int col = 0;
    metrics.project_id = stmt.column_int(col++);        // project_id
    metrics.name       = stmt.column_text(col++);       // name
    metrics.day        = stmt.column_int(col++);        // day
    metrics.month      = stmt.column_int(col++);        // month
    metrics.year       = stmt.column_int(col++);        // year
    metrics.hour       = stmt.column_int(col++);        // hour
    metrics.minute     = stmt.column_int(col++);        // minute
    metrics.second     = stmt.column_int(col++);        // second
    metrics.duration_days = stmt.column_double(col++);  // duration_days

    results.push_back(std::move(metrics));
  }

  return results;
}

}  // namespace project_time_tracking

